import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void oneEdgeWithWeightOne() {
        // 0 --(w=0)--> 1 --(w=1)--> 2; min cost 0→2 is 1
        int[][] edges = {{0,1,0},{1,2,1}};
        assertEquals(1, new Solution().zeroOneBfs(3, edges, 0, 2));
    }

    @Test
    void allZeroEdges_costIsZero() {
        int[][] edges = {{0,1,0},{1,2,0},{2,3,0}};
        assertEquals(0, new Solution().zeroOneBfs(4, edges, 0, 3));
    }

    @Test
    void srcEqualsDst_returnsZero() {
        int[][] edges = {{0,1,1}};
        assertEquals(0, new Solution().zeroOneBfs(2, edges, 0, 0));
    }

    @Test
    void unreachable_returnsMinusOne() {
        // Only edge goes 0→1; cannot reach 2
        int[][] edges = {{0,1,1}};
        assertEquals(-1, new Solution().zeroOneBfs(3, edges, 0, 2));
    }

    @Test
    void preferZeroWeightDetour() {
        // Direct 0→3 costs 1; detour 0→1→2→3 costs 0+0+0=0
        int[][] edges = {{0,3,1},{0,1,0},{1,2,0},{2,3,0}};
        assertEquals(0, new Solution().zeroOneBfs(4, edges, 0, 3));
    }

    @Test
    void noEdges_sameNode() {
        int[][] edges = {};
        assertEquals(0, new Solution().zeroOneBfs(1, edges, 0, 0));
    }

    @Test
    void directedEdge_noReturnPath() {
        // Edge 0→1 exists; 1 cannot reach 0
        int[][] edges = {{0,1,1}};
        assertEquals(-1, new Solution().zeroOneBfs(2, edges, 1, 0));
    }
}
